def sortedArrayToBST(nums: List[int]) -> Optional[object]:
    def build(left: int, right: int) -> Optional[object]:
        if left > right:
            return None
        mid = left + (right - left) // 2
        root = type('TreeNode', (), {'val': nums[mid], 'left': None, 'right': None})()
        root.left = build(left, mid - 1)
        root.right = build(mid + 1, right)
        return root

    return build(0, len(nums) - 1)

